const parts = [$.input.targetIndustry, $.input.targetLocation];
const staticTerms = "companies  hiring growing";
return { query: parts.filter(Boolean).join(" ") + " " + staticTerms };

const results = $.steps.findProspects.response.results || [];
const prospects = results.map((r, i) => {
  return {
    index: i + 1,
    title: r.title || 'Unknown Company',
    url: r.url || '',
    snippet: (r.text || '').slice(0, 500)
  };
}).filter(p => p.url.length > 0);
return { prospects, count: prospects.length };

const prospects = $.steps.extractUrls.output.prospects || [];
const iterations = $.steps.scrapeProspects.response.iterations || [];

let compiled = '';
prospects.forEach((p, i) => {
  compiled += '--- PROSPECT ' + p.index + ' ---\n';
  compiled += 'Company: ' + p.title + '\n';
  compiled += 'URL: ' + p.url + '\n';
  compiled += 'Search Snippet: ' + p.snippet + '\n';
  if (iterations[i] && iterations[i].scrapeOne && iterations[i].scrapeOne.response) {
    const scrapeData = iterations[i].scrapeOne.response;
    const content = (typeof scrapeData === 'string') ? scrapeData : JSON.stringify(scrapeData);
    compiled += 'Website Content: ' + content.slice(0, 2000) + '\n';
  }
  compiled += '\n';
});

return { compiled: compiled.slice(0, 30000), prospectCount: prospects.length };

const d = $.steps.compileProspectData.output;
const icp = $.input.idealCustomerProfile;
const industry = $.input.targetIndustry;

let prompt = 'You are a senior sales development representative. Qualify and score these prospects for cold outreach.\n\n';
prompt += 'IDEAL CUSTOMER PROFILE: ' + icp + '\n';
prompt += 'TARGET INDUSTRY: ' + industry + '\n';
prompt += 'TARGET LOCATION: ' + ($.input.targetLocation || 'United States') + '\n\n';
prompt += 'PROSPECT DATA (' + d.prospectCount + ' prospects):\n';
prompt += d.compiled + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Score each prospect 1-100 based on ICP fit\n';
prompt += '- Classify: hot (80+), warm (50-79), cold (below 50)\n';
prompt += '- Extract: company name, estimated size, key decision maker title, contact approach\n';
prompt += '- Generate a personalized opening line for each prospect\n';
prompt += '- Identify pain points that match our offering\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "leads": [\n';
prompt += '    {\n';
prompt += '      "company": "company name",\n';
prompt += '      "url": "website url",\n';
prompt += '      "score": 85,\n';
prompt += '      "classification": "hot|warm|cold",\n';
prompt += '      "estimatedSize": "10-50|50-200|200-1000|1000+",\n';
prompt += '      "decisionMaker": "likely title to contact",\n';
prompt += '      "painPoints": ["pain 1", "pain 2"],\n';
prompt += '      "openingLine": "personalized cold call opener",\n';
prompt += '      "approach": "recommended outreach strategy"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "totalLeads": 0,\n';
prompt += '  "hotLeads": 0,\n';
prompt += '  "warmLeads": 0,\n';
prompt += '  "coldLeads": 0,\n';
prompt += '  "pipelineSummary": "brief pipeline summary"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiQualify.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { leads: [], totalLeads: 0, hotLeads: 0, warmLeads: 0, coldLeads: 0, pipelineSummary: raw }; }

const ai = $.steps.parseAI.output;
const leads = ai.leads || [];

const header = ['Company', 'URL', 'Score', 'Classification', 'Est. Size', 'Decision Maker', 'Pain Points', 'Opening Line', 'Approach'];
const rows = leads.map(l => [
  l.company || 'Unknown',
  l.url || '',
  String(l.score || 0),
  l.classification || 'cold',
  l.estimatedSize || 'Unknown',
  l.decisionMaker || 'N/A',
  (l.painPoints || []).join('; '),
  l.openingLine || '',
  l.approach || ''
]);

const allRows = [header].concat(rows);
return { values: allRows, leadCount: leads.length, hotCount: ai.hotLeads || 0, summary: ai.pipelineSummary || '' };
